import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';

// ✅ Import Chart.js components
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

// ✅ Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
);

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    totalUsers: 0,
    avgSalary: 0,
    highestSalary: 0,
    lowestSalary: 0,
    predictions: []
  });

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        console.log("API Response:", res.data);
        setStats(res.data);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  // Wait until predictions are loaded
  if (!stats.predictions) return <p>Loading...</p>;

  // Bar Chart Data
  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [
      {
        label: "Predictions",
        data: [
          stats.predictions.filter(p => p.salary < 40000).length,
          stats.predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
          stats.predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
          stats.predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
          stats.predictions.filter(p => p.salary >= 100000).length,
        ],
        backgroundColor: ["#36A2EB","#6A5ACD","#FFA07A","#9370DB","#1E90FF"]
      }
    ]
  };

  // Pie Chart Data
  const pieData = {
    labels: ["Entry", "Intermediate", "Experienced", "Post-Graduate"],
    datasets: [
      {
        data: [
          stats.predictions.filter(p => p.experience === "Entry").length,
          stats.predictions.filter(p => p.experience === "Intermediate").length,
          stats.predictions.filter(p => p.experience === "Experienced").length,
          stats.predictions.filter(p => p.experience === "Post-Graduate").length
        ],
        backgroundColor: ["#4e73df","#f6c23e","#1cc88a","#e74a3b"]
      }
    ]
  };

  return (
    <div className="dashboard-container">
      <div className="sidebar">
        <h2>Admin</h2>
        <ul>
          <li>Dashboard</li>
          <li>Manage Users</li>
          <li>Reports</li>
          <li>Settings</li>
        </ul>
      </div>

      <div className="main-content">
        <div className="navbar"><h1>Admin Dashboard</h1></div>

        <div className="cards">
          <div className="card card1"><p>Avg Salary</p><h2>₹{stats.avgSalary.toFixed(0)}</h2></div>
          <div className="card card2"><p>Highest Salary</p><h2>₹{stats.highestSalary}</h2></div>
          <div className="card card3"><p>Lowest Salary</p><h2>₹{stats.lowestSalary}</h2></div>
          <div className="card card4"><p>Total Users</p><h2>{stats.totalUsers}</h2></div>
        </div>

        <div className="charts">
          <div className="chart"><h3>Salary Distribution</h3><Bar data={barData} /></div>
          <div className="chart"><h3>Experience Level</h3><Pie data={pieData} /></div>
        </div>

        <div className="table-section">
          <h3>Recent Predictions</h3>
          <table>
            <thead><tr><th>Email</th><th>Role</th><th>Location</th><th>Salary</th></tr></thead>
            <tbody>
              {stats.predictions.map((p, idx) => (
                <tr key={idx}>
                  <td>{p.email}</td>
                  <td>{p.role}</td>
                  <td>{p.location}</td>
                  <td>₹{p.salary}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
